// Step 1: Parse source list
const sources = JSON.parse($input.first().json.rss_sources);
const results = [];

// Step 2: Keyword filters per category
const KEYWORDS = {
  agentic_ai: ['agentic','ai agent','multi-agent','llm','large language model','generative ai','on-device ai','autonomous agent','inference','copilot','anthropic','openai','gemini'],
  chips_soc:  ['soc','chipset','modem','baseband','qualcomm','mediatek','exynos','snapdragon','dimensity','npu','ai accelerator','semiconductor','tsmc','arm','risc-v'],
  mobile:     ['smartphone','5g phone','flagship','android','iphone','galaxy','pixel','oem','xiaomi','oppo','vivo'],
  '5g_cpe':   ['5g','cpe','fixed wireless','fwa','6g','open ran','o-ran','vran','mmwave','5g-advanced','release 19','release 20'],
  csp_cloud:  ['cloud','aws','azure','google cloud','datacenter','hyperscaler','kubernetes','edge computing']
};

// Step 3: Date cutoff — last 24 hours
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);

// Step 4: Fetch each RSS feed
for (const src of sources) {
  try {
    const resp = await $http.request({ method: 'GET', url: src.url, timeout: 15000,
      headers: { 'User-Agent': 'SOC-Planning-Agent-n8n/1.0' } });

    // Parse RSS/Atom XML (n8n provides xmlParser helper)
    const xml = this.helpers.xml.parse ? await this.helpers.xml.parse(resp) : resp;
    const items = xml?.rss?.channel?.[0]?.item || xml?.feed?.entry || [];
    const keywords = KEYWORDS[src.category] || [];

    for (const item of items) {
      const title   = (item.title?.[0] || item.title || '').toString();
      const link    = (item.link?.[0] || item.link?.['$']?.href || '').toString();
      const desc    = (item.description?.[0] || item.summary?.[0] || '').toString().replace(/<[^>]+>/g,' ').trim();
      const pubRaw  = (item.pubDate?.[0] || item.published?.[0] || item.updated?.[0] || '').toString();
      const pubDate = pubRaw ? new Date(pubRaw) : null;

      // Date filter
      if (pubDate && pubDate < cutoff) continue;

      // Keyword filter
      const text = (title + ' ' + desc).toLowerCase();
      const match = keywords.some(kw => text.includes(kw));
      if (!match) continue;

      results.push({
        category: src.category,
        source:   src.source,
        title:    title.slice(0, 200),
        url:      link,
        summary:  desc.slice(0, 500),
        published: pubDate ? pubDate.toISOString().slice(0, 10) : pubRaw
      });
    }
  } catch(e) {
    // Individual feed failure — log and continue (don't fail the whole workflow)
    console.log(`RSS fetch failed [${src.source}]: ${e.message}`);
  }
}

// Step 5: Group by category
const grouped = {};
for (const art of results) {
  if (!grouped[art.category]) grouped[art.category] = [];
  grouped[art.category].push(art);
}

// Step 6: Return one item per category (for next node to iterate)
const output = Object.entries(grouped).map(([category, articles]) => ({
  json: { category, articles, article_count: articles.length }
}));

if (output.length === 0) {
  return [{ json: { category: null, articles: [], article_count: 0, message: 'No new articles in last 24h' } }];
}

return output;

