// Serper fallback: search when RSS feeds fail entirely
const category = $input.first().json.category || 'agentic_ai';
const SEARCH_QUERIES = {
  agentic_ai: 'agentic AI agent LLM autonomous 2026 site:techcrunch.com OR site:venturebeat.com',
  chips_soc:  'SoC chipset AI accelerator semiconductor 2026 site:eetimes.com OR site:semianalysis.com',
  mobile:     'smartphone 5G flagship Android 2026 site:gsmarena.com OR site:theverge.com',
  '5g_cpe':   '5G CPE O-RAN telecom 2026 site:lightreading.com OR site:rcrwireless.com',
  csp_cloud:  'cloud AI infrastructure hyperscaler 2026 site:thenewstack.io'
};
const today = new Date();
const after  = new Date(today - 3 * 86400000).toISOString().slice(0,10);

try {
  const resp = await $http.request({
    method: 'POST',
    url: 'https://google.serper.dev/news',
    headers: { 'X-API-KEY': $env.SERPER_API_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ q: (SEARCH_QUERIES[category] || SEARCH_QUERIES.agentic_ai) + ` after:${after}`, num: 10 })
  });
  const articles = (resp.news || []).map(r => ({
    category, source: r.source, title: r.title, url: r.link, summary: r.snippet, published: r.date || after
  }));
  return [{ json: { category, articles, article_count: articles.length, via: 'serper_fallback' } }];
} catch(e) {
  return [{ json: { category, articles: [], article_count: 0, error: e.message } }];
}
